        "### Crescimento populacional\n",
        "\n",
        "import math\n",
        "import matplotlib.pyplot as plt\n",
        "\n",
        "# 1. Dados do problema\n",
        "taxa = 0.03        # Taxa de crescimento de 3% ao ano\n",
        "multiplicador = 2  # Queremos descobrir quando a população dobra (Pt = 2 * P0)\n",
        "\n",
        "# População do ano base (P0).\n",
        "# Escolhi 1000 como exemplo para podermos visualizar no gráfico.\n",
        "P0 = 1000\n",
        "\n",
        "# 2. A fórmula exata isolando o tempo (t) com logaritmos\n",
        "t = math.log(multiplicador) / math.log(1 + taxa)\n",
        "\n",
        "# Exibindo o resultado no terminal\n",
        "print(\"-\" * 40)\n",
        "print(\"CÁLCULO DE CRESCIMENTO POPULACIONAL\")\n",
        "print(\"-\" * 40)\n",
        "print(f\"Taxa de crescimento: {taxa * 100}% ao ano\")\n",
        "print(f\"Tempo exato para DOBRAR a população: {t:.2f} anos\")\n",
        "print(\"-\" * 40)\n",
        "\n",
        "# 3. Gerando os dados para o Gráfico\n",
        "# Cria uma lista de anos do ano 0 até o ano final calculado\n",
        "anos_lista = list(range(int(t) + 2))\n",
        "\n",
        "# Calcula a população para cada ano usando a fórmula: Pt = P0 * (1.03)^t\n",
        "evolucao_populacao = [P0 * ((1 + taxa) ** ano) for ano in anos_lista]\n",
        "\n",
        "# 4. Configurando e exibindo o Gráfico\n",
        "plt.figure(figsize=(10, 6))\n",
        "plt.plot(anos_lista, evolucao_populacao, color='purple', linewidth=2, label='Curva de Crescimento')\n",
        "\n",
        "# Linhas de marcação para o momento em que a população dobra\n",
        "populacao_dobrada = P0 * multiplicador\n",
        "plt.axhline(y=populacao_dobrada, color='red', linestyle='--', label=f'População Dobrada ({populacao_dobrada} hab.)')\n",
        "plt.axvline(x=t, color='green', linestyle='--', label=f'Tempo Necessário ({t:.1f} anos)')\n",
        "\n",
        "# Detalhes visuais do gráfico\n",
        "plt.title('Evolução do Crescimento Populacional (3% a.a.)')\n",
        "plt.xlabel('Tempo (Anos)')\n",
        "plt.ylabel('Número de Habitantes (Exemplo)')\n",
        "plt.legend()\n",
        "plt.grid(True)\n",
        "\n",
        "# Mostra o gráfico na tela\n",
        "plt.show()\n",
        "\n",
        "import math\n",
        "\n",
        "def calcular_tempo_crescimento():\n",
        "    print(\"=\" * 50)\n",
        "    print(\"   CALCULADORA UNIVERSAL DE CRESCIMENTO EXPONENCIAL\")\n",
        "    print(\"=\" * 50)\n",
        "\n",
        "    # 1. Coletando os dados do usuário\n",
        "    p0 = float(input(\"Digite a população inicial (Ex: 1000): \"))\n",
        "    pt = float(input(\"Digite a população alvo (Ex: 2000 para dobrar): \"))\n",
        "    taxa_percentual = float(input(\"Digite a taxa de crescimento anual em % (Ex: 3): \"))\n",
        "\n",
