        "    print(\"-\" * 50)\n",
        "    print(f\"TEMPO NECESSÁRIO: {t:.2f} anos\")\n",
        "    print(\"=\" * 50)\n",
        "\n",
        "# Rodando o programa\n",
        "calcular_tempo_crescimento()"
